def test_decision_table_assigned_and_unassigned_same_clinician(
    mixed_clinician_token, assigned_patient_id, unassigned_patient_id, api_client
):
    headers = {"Authorization": f"Bearer {mixed_clinician_token}"}

    resp_assigned = api_client.get(f"/Patient/{assigned_patient_id}", headers=headers)
    assert resp_assigned.status_code == 200
    assert resp_assigned.json()["id"] == assigned_patient_id

    resp_unassigned = api_client.get(f"/Patient/{unassigned_patient_id}", headers=headers)
    assert resp_unassigned.status_code == 403
    body = resp_unassigned.json()
    assert body.get("resourceType") != "Patient", (
        "Unassigned patient data must not be returned"
    )

def test_state_transition_access_revoked_after_unassignment(
    stc_clinician_token, stc_clinician_id, stc_patient_id,
    api_client, assign_patient_to_clinician, unassign_patient_from_clinician
):
    assign_patient_to_clinician(clinician_id=stc_clinician_id, patient_id=stc_patient_id)
    headers = {"Authorization": f"Bearer {stc_clinician_token}"}

    resp_before = api_client.get(f"/Patient/{stc_patient_id}", headers=headers)
    assert resp_before.status_code == 200, (
        "Read must succeed when clinician is assigned (pre-transition state)"
    )
    assert resp_before.json()["id"] == stc_patient_id

    unassign_patient_from_clinician(clinician_id=stc_clinician_id, patient_id=stc_patient_id)

    resp_after = api_client.get(f"/Patient/{stc_patient_id}", headers=headers)
    assert resp_after.status_code == 403, (
        "Read must be denied after assignment is revoked (post-transition state)"
    )
    body = resp_after.json()
    assert body.get("resourceType") != "Patient", (
        "Patient data must not be disclosed after unassignment"
    )
